code = """import json
import pandas as pd
from collections import defaultdict
import re

# Load 2019 second half patents
file_path_2019 = locals()['var_functions.query_db:8']
with open(file_path_2019, 'r') as f:
    de_patents_2019 = json.load(f)

# Extract CPC level 4 codes from 2019 second half patents
codes_2019_level4 = set()
for patent in de_patents_2019:
    cpc_data = patent.get('cpc', '[]')
    try:
        cpc_list = json.loads(cpc_data)
        for cpc_item in cpc_list:
            code = cpc_item.get('code', '')
            if code and '/' in code:
                level4 = code.split('/')[0]
                codes_2019_level4.add(level4)
    except:
        continue

print('CPC Level 4 codes from 2019 second half: ' + str(len(codes_2019_level4)))
print('Sample codes: ' + str(list(codes_2019_level4)[:10]))

result = {
    'cpc_level4_codes_2019': list(codes_2019_level4),
    'count': len(codes_2019_level4)
}

print('__RESULT__:')
print(json.dumps(result))"""

